const htmlStr = $input.first().json.data;
const match = htmlStr.match(/href="(https:\/\/[^"]+?\.pdf)"/);
if (!match) {
  throw new Error("No PDF links found");
}
return { pdfUrl: match[1] };

const text = $input.first().json.text;
const lines = text.split('\n');
const pattern = /^(.*?)\s+(KILO|BULTO|BULTOS|CANASTILLA|CAJA|ATADO|PAQUETE|BOLSA|LIBRA|LIBRAS|UNIDAD)\s+(\d+)\s+(KILO|BULTO|BULTOS|CANASTILLA|CAJA|ATADO|PAQUETE|BOLSA|LIBRA|LIBRAS|UNIDAD)\s+\$([\d,]+)\s+\$([\d,]+)(?:\s+\$([\d,]+))?\s+(Estable|Subio|Bajo)/i;

const items = [];
for (const line of lines) {
  const match = pattern.exec(line.trim());
  if (match) {
    items.push({
      json: {
        producto: match[1].trim(),
        presentacion: match[2].trim(),
        cantidad: parseInt(match[3]),
        unidad: match[4].trim(),
        precio_extra: parseInt(match[5].replace(/,/g, '')),
        precio_primera: parseInt(match[6].replace(/,/g, '')),
        precio_unidad: match[7] ? parseInt(match[7].replace(/,/g, '')) : 0,
        variacion: match[8].trim(),
        ciudad: "Bogotá"
      }
    });
  }
}
return items;
